#include <stdio.h>
#include <limits.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, B, C;
        scanf("%d %d %d", &N, &B, &C);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        long long dp[N];
        for (int i = 0; i < N; i++) {
            dp[i] = LLONG_MAX;
        }
        dp[C - 1] = 0;
        for (int i = 0; i < B; i++) {
            for (int j = 0; j < N; j++) {
                if (dp[j] != LLONG_MAX) {
                    for (int k = 0; k < N; k++) {
                        if (A[k] >= A[j] - i - 1 && A[k] <= A[j] + i + 1) {
                            dp[k] = (dp[k] < dp[j] + (i + 1) * (i + 1)) ? dp[k] : dp[j] + (i + 1) * (i + 1);
                        }
                    }
                }
            }
        }
        long long ans = LLONG_MAX;
        for (int i = 0; i < N; i++) {
            ans = (ans < dp[i]) ? ans : dp[i];
        }
        printf("%lld\n", ans);
    }
    return 0;
}

