import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int B = sc.nextInt();
            int C = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            long[] dp = new long[N];
            for (int i = 0; i < N; i++) {
                dp[i] = Long.MAX_VALUE;
            }
            dp[C - 1] = 0;
            for (int i = 0; i < B; i++) {
                for (int j = 0; j < N; j++) {
                    if (dp[j] != Long.MAX_VALUE) {
                        for (int k = 0; k < N; k++) {
                            if (A[k] >= A[j] - i - 1 && A[k] <= A[j] + i + 1) {
                                dp[k] = (dp[k] < dp[j] + (i + 1) * (i + 1)) ? dp[k] : dp[j] + (i + 1) * (i + 1);
                            }
                        }
                    }
                }
            }
            long ans = Long.MAX_VALUE;
            for (int i = 0; i < N; i++) {
                ans = (ans < dp[i]) ? ans : dp[i];
            }
            System.out.println(ans);
        }
    }
