    dp = [float('inf')] * N
    dp[C - 1] = 0
    for i in range(B):
        for j in range(N):
            if dp[j] != float('inf'):
                for k in range(N):
                    if A[k] >= A[j] - i - 1 and A[k] <= A[j] + i + 1:
                        dp[k] = min(dp[k], dp[j] + (i + 1) * (i + 1))
    ans = float('inf')
    for i in range(N):
        ans = min(ans, dp[i])
