const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, B, C] = readline().split(' ').map(Number);
    const A = readline().split(' ').map(Number);
    const dp = new Array(N).fill(Infinity);
    dp[C - 1] = 0;
    for (let j = 0; j < B; j++) {
        for (let k = 0; k < N; k++) {
            if (dp[k] !== Infinity) {
                for (let l = 0; l < N; l++) {
                    if (A[l] >= A[k] - j - 1 && A[l] <= A[k] + j + 1) {
                        dp[l] = Math.min(dp[l], dp[k] + (j + 1) * (j + 1));
                    }
                }
            }
        }
    }
    let ans = Infinity;
    for (let j = 0; j < N; j++) {
        ans = Math.min(ans, dp[j]);
    }
    console.log(ans);
}

